import{_ as s,c as n,o as a,a as l}from"./app.87c00501.js";const e='{"title":"Flex","description":"","frontmatter":{},"headers":[{"level":2,"title":"Flex容器","slug":"flex容器"},{"level":3,"title":"flex-direction: 决定主轴的方向(即项目的排列方向)","slug":"flex-direction-决定主轴的方向-即项目的排列方向"},{"level":3,"title":"flex-wrap: 决定容器内项目是否可换行","slug":"flex-wrap-决定容器内项目是否可换行"},{"level":3,"title":"justify-content：定义了项目在主轴的对齐方式","slug":"justify-content：定义了项目在主轴的对齐方式"},{"level":3,"title":"align-items:定义了项目在交叉轴上的对齐方式","slug":"align-items-定义了项目在交叉轴上的对齐方式"},{"level":3,"title":"align-content","slug":"align-content"},{"level":2,"title":"Flex item","slug":"flex-item"},{"level":3,"title":"order:定义项目在容器中的排列顺序，数值越小，排列越靠前，默认值为 0","slug":"order-定义项目在容器中的排列顺序，数值越小，排列越靠前，默认值为-0"},{"level":3,"title":"flex-basis","slug":"flex-basis"},{"level":3,"title":"flex-grow","slug":"flex-grow"},{"level":3,"title":"flex-shrink","slug":"flex-shrink"},{"level":3,"title":"align-self","slug":"align-self"}],"relativePath":"docs/css/Flex.md"}',t={},p=[l('<h1 id="flex" tabindex="-1">Flex <a class="header-anchor" href="#flex" aria-hidden="true">#</a></h1><h2 id="flex容器" tabindex="-1">Flex容器 <a class="header-anchor" href="#flex容器" aria-hidden="true">#</a></h2><div class="language-css"><pre><code><span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">container</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#B2CCD6;">display</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> flex | inline-flex</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;">       //可以有两种取值</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div><p><img src="/assets/8-block-vs-inline.dd91dd12.png" alt=""></p><p><strong>当设置 flex 布局之后，子元素的 float、clear、vertical-align 的属性将会失效</strong></p><p>flex 容器只对下<strong>一</strong>层生效</p><p>有下面六种属性可以设置在容器上，它们分别是：</p><ol><li>flex-direction</li><li>flex-wrap</li><li>flex-flow（flex-direction 和 flex-wrap 的简写形式）</li><li>justify-content</li><li>align-items</li><li>align-content</li></ol><h3 id="flex-direction-决定主轴的方向-即项目的排列方向" tabindex="-1">flex-direction: 决定主轴的方向(即项目的排列方向) <a class="header-anchor" href="#flex-direction-决定主轴的方向-即项目的排列方向" aria-hidden="true">#</a></h3><div class="language-css"><pre><code><span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">container</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#B2CCD6;">flex-direction</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> row | row-reverse | column | column-reverse</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div><ul><li>row: 主轴为水平方向</li><li>column：主轴为垂直方向</li></ul><h3 id="flex-wrap-决定容器内项目是否可换行" tabindex="-1">flex-wrap: 决定容器内项目是否可换行 <a class="header-anchor" href="#flex-wrap-决定容器内项目是否可换行" aria-hidden="true">#</a></h3><div class="language-css"><pre><code><span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">container</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#B2CCD6;">flex-wrap</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> nowrap | wrap | wrap-reverse</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div><ul><li>nowrap：默认值，主轴尺寸固定时，当空间不足时，item尺寸会随之调整</li><li>wrap: item主轴总尺寸超出容器时换行</li></ul><h3 id="justify-content：定义了项目在主轴的对齐方式" tabindex="-1">justify-content：定义了项目在主轴的对齐方式 <a class="header-anchor" href="#justify-content：定义了项目在主轴的对齐方式" aria-hidden="true">#</a></h3><div class="language-css"><pre><code><span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">container</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#B2CCD6;">justify-content</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> flex-start | flex-end | center | space-between | space-around</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div><div class="language-css"><pre><code><span class="line"><span style="color:#676E95;font-style:italic;">/* 对齐方式 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: center;     </span><span style="color:#676E95;font-style:italic;">/* 居中排列 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: start;      </span><span style="color:#676E95;font-style:italic;">/* 从行首开始排列 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: end;        </span><span style="color:#676E95;font-style:italic;">/* 从行尾开始排列 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: </span><span style="color:#FFCB6B;">flex-start</span><span style="color:#A6ACCD;">; </span><span style="color:#676E95;font-style:italic;">/* 从行首起始位置开始排列 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: </span><span style="color:#FFCB6B;">flex-end</span><span style="color:#A6ACCD;">;   </span><span style="color:#676E95;font-style:italic;">/* 从行尾位置开始排列 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: left;       </span><span style="color:#676E95;font-style:italic;">/* 一个挨一个在对齐容器得左边缘 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: right;      </span><span style="color:#676E95;font-style:italic;">/* 元素以容器右边缘为基准，一个挨着一个对齐, */</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">/* 基线对齐 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: baseline;</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: first baseline;</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: last baseline;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">/* 分配弹性元素方式 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: </span><span style="color:#FFCB6B;">space-between</span><span style="color:#A6ACCD;">;  </span><span style="color:#676E95;font-style:italic;">/* 均匀排列每个元素</span></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">                                   首个元素放置于起点，末尾元素放置于终点 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: </span><span style="color:#FFCB6B;">space-around</span><span style="color:#A6ACCD;">;  </span><span style="color:#676E95;font-style:italic;">/* 均匀排列每个元素</span></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">                                   每个元素周围分配相同的空间 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: </span><span style="color:#FFCB6B;">space-evenly</span><span style="color:#A6ACCD;">;  </span><span style="color:#676E95;font-style:italic;">/* 均匀排列每个元素</span></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">                                   每个元素之间的间隔相等 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: stretch;       </span><span style="color:#676E95;font-style:italic;">/* 均匀排列每个元素</span></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">                                   &#39;auto&#39;-sized 的元素会被拉伸以适应容器的大小 */</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">/* 溢出对齐方式 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: safe center;</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: unsafe center;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#676E95;font-style:italic;">/* 全局值 */</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: inherit;</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: initial;</span></span>\n<span class="line"><span style="color:#FFCB6B;">justify-content</span><span style="color:#A6ACCD;">: unset;</span></span>\n<span class="line"></span></code></pre></div><p><img src="/assets/12-justify-content-row.bfe207db.png" alt=""></p><p><img src="/assets/14-space-around-vs-space-evenly.adc5bfd9.jpg" alt=""></p><h3 id="align-items-定义了项目在交叉轴上的对齐方式" tabindex="-1">align-items:定义了项目在交叉轴上的对齐方式 <a class="header-anchor" href="#align-items-定义了项目在交叉轴上的对齐方式" aria-hidden="true">#</a></h3><ul><li>justify-content 定义了项目在主轴的对齐方式</li><li>align-items定义了项目在交叉轴上的对齐方式</li></ul><p><img src="/assets/15-align-items-row.8696b287.png" alt=""></p><p><strong>默认值为 stretch 即如果项目未设置高度或者设为 auto，将占满整个容器的高度</strong></p><h3 id="align-content" tabindex="-1">align-content <a class="header-anchor" href="#align-content" aria-hidden="true">#</a></h3><p>当flex-wrap被设置为wrap时，align-content定义了在交叉轴上的对齐方式</p><p><img src="/assets/18-align-content.2dcf4f39.png" alt=""></p><h2 id="flex-item" tabindex="-1">Flex item <a class="header-anchor" href="#flex-item" aria-hidden="true">#</a></h2><h3 id="order-定义项目在容器中的排列顺序，数值越小，排列越靠前，默认值为-0" tabindex="-1">order:定义项目在容器中的排列顺序，数值越小，排列越靠前，默认值为 0 <a class="header-anchor" href="#order-定义项目在容器中的排列顺序，数值越小，排列越靠前，默认值为-0" aria-hidden="true">#</a></h3><p><img src="/assets/20-order.d4f605f0.png" alt=""></p><h3 id="flex-basis" tabindex="-1">flex-basis <a class="header-anchor" href="#flex-basis" aria-hidden="true">#</a></h3><p>相当于width</p><h3 id="flex-grow" tabindex="-1">flex-grow <a class="header-anchor" href="#flex-grow" aria-hidden="true">#</a></h3><p><img src="/assets/22-flex-grow-calculation.54b68cf9.png" alt=""></p><h3 id="flex-shrink" tabindex="-1">flex-shrink <a class="header-anchor" href="#flex-shrink" aria-hidden="true">#</a></h3><p><img src="/assets/24-flex-shrink-calculation.b548f927.png" alt=""></p><h3 id="align-self" tabindex="-1">align-self <a class="header-anchor" href="#align-self" aria-hidden="true">#</a></h3><p>强制这一个item实现不同的交叉轴对齐方式</p><p><img src="/assets/28-align-self.d609f7a2.png" alt=""></p>',38)];var o=s(t,[["render",function(s,l,e,t,o,i){return a(),n("div",null,p)}]]);export{e as __pageData,o as default};
